1	package aisuite
2	
3	import (
4		"net/http"
5	
6		"github.com/gin-gonic/gin"
7		"gorm.io/gorm"
8	
9		"code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/backend/aisuite/controller"
10		"code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/backend/cluster/manager"
11		"code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/models"
12		"code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/models/aisuite"
13	
14		"code.srdcloud.cn/TDP-PaaS/TDP-CODE/paas-controller/pkg/log"
15	)
16	
17	type Server struct {
18		controller *controller.Controller
19	}
20	
21	func newServer(db *gorm.DB, apiserverGetter manager.ApiserverGetter) (*Server, error) {
22		newController, err := controller.NewController(db, apiserverGetter)
23		if err != nil {
24			return nil, err
25		}
26		return &Server{controller: newController}, nil
27	}
28	
29	func (s *Server) ListAISuites(ctx *gin.Context) {
30		req := &aisuite.ListAISuitesReq{}
31		if err := ctx.ShouldBindQuery(req); err != nil {
32			log.Errorf("invalid query parameters: %v", err)
33			ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusBadRequest, err))
34			return
35		}
36	
37		aiSuites, err := s.controller.ListAISuites(ctx, req.ClusterCode)
38		if err != nil {
39			log.Errorf("failed to list AI Suites: %v", err)
40			ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusInternalServerError, err))
41			return
42		}
43	
44		ctx.JSON(http.StatusOK, models.WrapSuccessResp(aiSuites))
45	}
46	
47	func (s *Server) GetAISuite(ctx *gin.Context) {
48		req := &aisuite.GetAISuiteReq{}
49		if err := ctx.ShouldBindQuery(req); err != nil {
50			log.Errorf("invalid query parameters: %v", err)
51			ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusBadRequest, err))
52			return
53		}
54		if err := ctx.ShouldBindUri(req); err != nil {
55			log.Errorf("invalid URI parameters: %v", err)
56			ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusBadRequest, err))
57			return
58		}
59	
60		aiSuite, err := s.controller.GetAISuite(ctx, req.ClusterCode, req.Name, req.ChartVersion, req.Namespace)
61		if err != nil {
62			log.Errorf("failed to get AI Suite: %v", err)
63			ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusInternalServerError, err))
64			return
65		}
66	
67		ctx.JSON(http.StatusOK, models.WrapSuccessResp(aiSuite))
68	}
69	
70	func (s *Server) GetAISuiteReadme(ctx *gin.Context) {
71		req := &aisuite.GetAISuiteReadmeReq{}
72		if err := ctx.ShouldBindQuery(req); err != nil {
73			log.Errorf("invalid query parameters: %v", err)
74			ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusBadRequest, err))
75			return
76		}
77		if err := ctx.ShouldBindUri(req); err != nil {
78			log.Errorf("invalid URI parameters: %v", err)
79			ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusBadRequest, err))
80			return
81		}
82	
83		readme, err := s.controller.GetAISuiteReadme(ctx, req.Name, req.ChartVersion)
84		if err != nil {
85			log.Errorf("failed to get AI Suite README: %v", err)
86			ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusInternalServerError, err))
87			return
88		}
89	
90		ctx.JSON(http.StatusOK, models.WrapSuccessResp(readme))
91	}
92	
93	func (s *Server) OperateAISuiteInCluster(ctx *gin.Context) {
94		var req aisuite.OperateAISuiteReq
95		if err := ctx.ShouldBindJSON(&req); err != nil {
96			log.Errorf("invalid request body: %v", err)
97			ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusBadRequest, err))
98			return
99		}
100		if err := ctx.ShouldBindUri(&req); err != nil {
101			log.Errorf("invalid URI parameters: %v", err)
102			ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusBadRequest, err))
103			return
104		}
105	
106		if err := s.controller.OperateAISuiteInCluster(ctx, &req); err != nil {
107			log.Errorf("failed to operate AI Suite in cluster: %v", err)
108			ctx.JSON(http.StatusOK, models.WrapFailedResp(http.StatusInternalServerError, err))
109			return
110		}
111	
112		// 操作成功后，返回套件详情而不是简单的成功消息
113		suiteResp, err := s.controller.GetAISuite(ctx, req.ClusterCode, req.Name, req.ChartVersion, req.Namespace)
114		if err != nil {
115			log.Errorf("failed to get AI Suite details after operation: %v", err)
116			// 降级处理：操作成功但获取详情失败，仍返回成功但不含详情
117			ctx.JSON(http.StatusOK, models.WrapSuccessResp(gin.H{}))
118			return
119		}
120	
121		ctx.JSON(http.StatusOK, models.WrapSuccessResp(suiteResp))
122	
123	}
