1	package harbor
2	
3	import (
4		"fmt"
5		"net/url"
6		"time"
7	
8		runtimeclient "github.com/go-openapi/runtime/client"
9		"github.com/mittwald/goharbor-client/v5/apiv2"
10		"github.com/mittwald/goharbor-client/v5/apiv2/pkg/config"
11	)
12	
13	// HarborClient 是对 Harbor API v2 客户端的封装
14	type HarborClient struct {
15		client *apiv2.RESTClient
16	}
17	
18	// NewHarborClient 根据地址、用户名、密码创建一个 Harbor 客户端
19	func NewHarborClient(addr, username, password string, opts *config.Options) (*HarborClient, error) {
20		if opts == nil {
21			opts = &config.Options{
22				Timeout:  5 * time.Second,
23				Page:     1,
24				PageSize: 10,
25			}
26		}
27	
28		client, err := newRESTClientV2(addr, username, password, opts)
29		if err != nil {
30			return nil, err
31		}
32	
33		return &HarborClient{client: client}, nil
34	}
35	
36	// newRESTClientV2 创建一个 Harbor REST 客户端
37	func newRESTClientV2(addr, username, password string, opts *config.Options) (*apiv2.RESTClient, error) {
38		harborURL, err := url.Parse(addr)
39		if err != nil {
40			return nil, fmt.Errorf("failed to parse harbor URL: %w", err)
41		}
42	
43		// 确保 URL 以 /api 结尾
44		if harborURL.Path == "" || harborURL.Path == "/" {
45			addr = fmt.Sprintf("%s/api", addr)
46		}
47	
48		harborURL, _ = url.Parse(addr)
49	
50		if harborURL.Scheme == "https" {
51			var optsTLS runtimeclient.TLSClientOptions
52			optsTLS.InsecureSkipVerify = true
53			client, err := runtimeclient.TLSClient(optsTLS)
54			if err != nil {
55				return nil, fmt.Errorf("failed to create TLS client: %w", err)
56			}
57			return apiv2.NewRESTClientForHostWithClient(addr, username, password, opts, client)
58		} else {
59			return apiv2.NewRESTClientForHost(addr, username, password, opts)
60		}
61	}
62	
63	// GetClient 返回底层的 REST 客户端，供高级操作使用
64	func (h *HarborClient) GetClient() *apiv2.RESTClient {
65		return h.client
66	}
67

