15	// ListRepositories 列出指定 Harbor 项目中的所有镜像仓库
16	func ListRepositories(ctx context.Context, registryConfig *db.Repository, projectName string, opts *config.Options) ([]*model.Repository, error) {
17		client, err := GetRegistryClient(registryConfig, opts)
18		if err != nil {
19			return nil, err
20		}
21	
22		repositories, err := client.GetClient().ListRepositories(ctx, projectName)
23		if err != nil {
24			return nil, fmt.Errorf("failed to list repositories from project %s in registry %s: %w", projectName, registryConfig.Name, err)
25		}
26	
27		return repositories, nil
28	}
29	
30	// GetRepository 获取指定 Harbor 项目中的单个镜像仓库详情
31	func GetRepository(ctx context.Context, registryConfig *db.Repository, projectName, repositoryName string, opts *config.Options) (*model.Repository, error) {
32		client, err := GetRegistryClient(registryConfig, opts)
33		if err != nil {
34			return nil, err
35		}
36	
37		repository, err := client.GetClient().GetRepository(ctx, projectName, repositoryName)
38		if err != nil {
39			return nil, fmt.Errorf("failed to get repository %s/%s from registry %s: %w", projectName, repositoryName, registryConfig.Name, err)
40		}
41	
42		return repository, nil
43	}
44	
45	// DeleteRepository 删除指定的镜像仓库
46	func DeleteRepository(ctx context.Context, registryConfig *db.Repository, projectName, repositoryName string) error {
47		client, err := GetRegistryClient(registryConfig, nil)
48		if err != nil {
49			return err
50		}
51	
52		err = client.GetClient().DeleteRepository(ctx, projectName, repositoryName)
53		if err != nil {
54			return fmt.Errorf("failed to delete repository %s/%s in registry %s: %w", projectName, repositoryName, registryConfig.Name, err)
55		}
56	
57		log.Infof("Deleted repository %s/%s in registry %s", projectName, repositoryName, registryConfig.Name)
58		return nil
59	}
60	
61	func GetSimpleRepoName(fullRepoName string) string {
62		// Harbor 的 repository 全称格式是 projectName/repoName，所以简单的 repoName 是全称去掉 projectName 和斜杠后的部分
63		// 例如：fullRepoName = "myproject/myrepo"，则简单 repoName 是 "myrepo"
64		parts := strings.SplitN(fullRepoName, "/", 2)
65		if len(parts) == 2 {
66			return parts[1]
67		}
68		return fullRepoName // 如果格式不符合预期，返回原始字符串
69	}
