24	
25	type Controller struct {
26		db              *gorm.DB
27		apiserverGetter manager.ApiserverGetter
28	}
29	
30	const (
31		suiteProjectPrefix  = "zzzz_internal_ai_suite"
32		suiteChartProject   = suiteProjectPrefix + "_helm_charts"
33		chartArtifactType   = "CHART"
34		jsonSchemaFileName  = "tap_aisuite_values.json"
35		readmeFileName      = "README.md"
36		aisuiteReleaseLabel = "DeployedBy=TAPAISuite"
37		maxSchemaSize       = 1024 * 1024 // 单位：字节
38		wait                = true
39		waitTimeout         = 10 * time.Minute
40		helmParamPrefix     = "tap_aisuite_"
41	)
42	
43	const (
44		deployStatusUndeployed = "undeployed"
45	)
46	
47	const (
48		ActionInstall   = "deploy"
49		ActionUpgrade   = "upgrade"
50		ActionUninstall = "uninstall"
51	)
52	
53	func NewController(db *gorm.DB, apiserverGetter manager.ApiserverGetter) (*Controller, error) {
54		return &Controller{
55			db:              db,
56			apiserverGetter: apiserverGetter,
57		}, nil
58	}
59	
60	func (c *Controller) ListAISuites(ctx *gin.Context, clusterCode string) (*aisuite.ListAISuitesResp, error) {
61		suiteRegistry, err := getSuiteRegistry(c.db)
62		var aiSuitesInRegistry []*aisuite.ProfileAISuite
63		if err != nil {
64			log.Errorf("failed to get suite registry: %v", err)
65		} else {
66			aiSuitesInRegistry, err = listAISuitesInRegistry(ctx, suiteRegistry)
67			if err != nil {
68				log.Errorf("failed to list AI Suites in registry: %v", err)
69			}
70		}
71	
72		aiSuitesInCluster, err := c.listAISuitesInCluster(clusterCode)
73		// 如果查询集群内套件失败，应该直接返回报错，防止用户下一步操作部署一个已经在集群里部署了的套件（因为用户看不到集群里的套件列表，以为没有，所以又部署了一个）
74		if err != nil {
75			log.Errorf("failed to list AI Suites in cluster: %v", err)
76			return nil, fmt.Errorf("failed to list AI Suites in cluster: %w", err)
77		}
78	
79		// 入参底层数组可能会被修改，如果后面要增加逻辑，注意处理
80		aiSuites := disruptiveMergeAiSuites(aiSuitesInRegistry, aiSuitesInCluster)
81		sort.Slice(aiSuites, func(i, j int) bool {
82			return aiSuites[i].Name < aiSuites[j].Name
83		})
84		return &aisuite.ListAISuitesResp{
85			Total: len(aiSuites),
86			Data:  aiSuites,
87		}, nil
88	}
89	
90	func (c *Controller) GetAISuite(ctx *gin.Context, clusterCode, name, chartVersion, namespace string) (*aisuite.GetAISuiteResp, error) {
91		// 从集群和registry中查询套件
92		suiteInCluster, err := c.getAISuiteInCluster(clusterCode, name, chartVersion, namespace)
93		if err != nil {
94			log.Errorf("encountered error while getting AI Suite in cluster: %v", err)
95			if namespace != "" {
96				return nil, fmt.Errorf("encountered error while getting AI Suite in cluster: %w", err)
97			}
98		}
99	
100		suiteInRegistry := new(aisuite.GetAISuiteResp)
101		suiteRegistry, err := getSuiteRegistry(c.db)
102		if err != nil {
103			log.Errorf("failed to get suite registry: %v", err)
104		} else {
105			suiteInRegistry, err = getAISuiteInRegistry(ctx, suiteRegistry, name, chartVersion)
106			if err != nil {
107				log.Errorf("encountered error while getting AI Suite in registry: %v", err)
108				suiteInRegistry = nil
109			}
110		}
111	
112		switch {
113		case suiteInCluster == nil && suiteInRegistry == nil:
114			return nil, fmt.Errorf("AI Suite %s not found in both cluster and registry", name)
115		case suiteInCluster != nil && suiteInRegistry == nil:
116			return suiteInCluster, nil
117		case suiteInCluster == nil && suiteInRegistry != nil:
118			return suiteInRegistry, nil
119		case suiteInCluster != nil && suiteInRegistry != nil:
120			if suiteInCluster.ProfileAISuite != nil && suiteInCluster.ProfileAISuite.Version != nil {
121				inBoth := false
122				for _, version := range suiteInRegistry.VersionList {
123					if version.DisplayVersion == suiteInCluster.ProfileAISuite.Version.DisplayVersion {
124						suiteInCluster.VersionList = suiteInRegistry.VersionList
125						inBoth = true
126						break
127					}
128				}
129				if !inBoth {
130					suiteInCluster.VersionList = append(suiteInCluster.VersionList, suiteInCluster.ProfileAISuite.Version)
131				}
132				// TODO: 用已部署套件的values的值覆盖schame中的默认值，提供给前端展示
133				// setValues, err := c.apiserverGetter.GetHelmReleaseValues(clusterCode, namespace, name, suiteInCluster.ProfileAISuite.Version.Revision, true)
134				// if err != nil {
135				// 	log.Errorf("failed to get helm release values: %v", err)
136				// }
137				// setValues中是嵌套map[string]interface{}的结构，需要转换成json字符串再赋值给CustomValueSchema中的
138			}
139			suiteInCluster.CustomValueSchema = suiteInRegistry.CustomValueSchema
140			return suiteInCluster, nil
141		}
142		return nil, nil
143	}
144	
145	func (c *Controller) GetAISuiteReadme(ctx context.Context, name, chartVersion string) (*aisuite.GetAISuiteReadmeResp, error) {
146		// 使用oras拉取chart，解压后读取其中的README.md, 作为套件的README内容
147		suiteRegistry, err := getSuiteRegistry(c.db)
148		if err != nil {
149			log.Errorf("failed to get suite registry: %v", err)
150			return nil, fmt.Errorf("failed to get suite registry: %w", err)
151		}
152		orasClient, err := oras.NewClient(suiteRegistry, oras.Insecure())
153		if err != nil {
154			log.Errorf("failed to create oras client: %v", err)
155			return nil, fmt.Errorf("failed to create oras client: %w", err)
156		}
157		artifactRef := fmt.Sprintf("%s/%s:%s", suiteChartProject, name, chartVersion)
158		readmeBytes, err := orasClient.PullFile(ctx, artifactRef, readmeFileName, maxSchemaSize)
159		if err != nil {
160			log.Errorf("failed to pull README.md for AI Suite %s:%s: %v", name, chartVersion, err)
161			return nil, fmt.Errorf("failed to pull README.md for AI Suite %s:%s: %w", name, chartVersion, err)
162		}
163		return &aisuite.GetAISuiteReadmeResp{Readme: string(readmeBytes)}, nil
164	}
165	
166	func (c *Controller) OperateAISuiteInCluster(ctx *gin.Context, req *aisuite.OperateAISuiteReq) error {
167		if req.Action == ActionUninstall {
168			// 执行卸载操作
169			if err := c.uninstallAISuiteInCluster(req.ClusterCode, req.Name, req.Namespace); err != nil {
170				return fmt.Errorf("failed to uninstall AI Suite %s in cluster %s: %w", req.Name, req.ClusterCode, err)
171			}
172			return nil
173		}
174	
175		switch req.Action {
176		case ActionInstall:
177			// 执行安装操作
178			if err := c.installAISuiteInCluster(req.ClusterCode, req.Name, req.ChartVersion, req.CustomValues); err != nil {
179				return fmt.Errorf("failed to install AI Suite %s in cluster %s: %w", req.Name, req.ClusterCode, err)
180			}
181		case ActionUpgrade:
182			// 执行升级操作
183			if err := c.upgradeAISuiteInCluster(req.ClusterCode, req.Namespace, req.Name, req.ChartVersion, req.CustomValues); err != nil {
184				return fmt.Errorf("failed to upgrade AI Suite %s in cluster %s: %w", req.Name, req.ClusterCode, err)
185			}
186		default:
187			return fmt.Errorf("unsupported operation: %s", req.Action)
188		}
189		return nil
190	}
191	
192	func (c *Controller) uninstallAISuiteInCluster(clusterCode, name, namespace string) error {
193		return c.apiserverGetter.UninstallRelease(clusterCode, namespace, name)
194	}
195	
196	func (c *Controller) installAISuiteInCluster(clusterCode, name, chartVersion string, customValues []*aisuite.CustomValues) error {
197		suiteRegistry, err := getSuiteRegistry(c.db)
198		if err != nil {
199			log.Errorf("failed to get suite registry: %v", err)
200			return fmt.Errorf("failed to get suite registry: %w", err)
201		}
202		registryHost := strings.TrimPrefix(suiteRegistry.Address, "https://")
203		registryHost = strings.TrimPrefix(registryHost, "http://")
204		repoChart := fmt.Sprintf("oci://%s/%s/%s", registryHost, suiteChartProject, name)
205		setValues := make(map[string]interface{})
206		req := &helm.InstallOrUpgradeReleaseRequest{
207			HelmRepository: helm.HelmRepository{
208				Host:     registryHost,
209				UserName: suiteRegistry.User,
210				Password: suiteRegistry.Password,
211			},
212			CreateNamespace: true,
213			Name:            name,
214			Wait:            wait,
215			Timeout:         waitTimeout,
216			RepoChart:       repoChart,
217			Version:         chartVersion,
218			Labels:          map[string]string{"DeployedBy": "TAPAISuite"},
219		}
220		for _, cv := range customValues {
221			switch cv.Name {
222			case helmParamPrefix + "namespace":
223				namespace, ok := cv.Value.(string)
224				if !ok {
225					return fmt.Errorf("invalid type for namespace value: expected string, got %T", cv.Value)
226				}
227				req.Namespace = namespace
228			case helmParamPrefix + "timeout":
229				waitTimeoutFloat, ok := cv.Value.(float64) // JSON numbers are unmarshaled into float64
230				if !ok {
231					return fmt.Errorf("invalid type for timeout value: expected int, got %T", cv.Value)
232				}
233				waitTimeout := util.ToInt(waitTimeoutFloat)
234				req.Timeout = time.Duration(waitTimeout) * time.Second
235			default:
236				expandDotKey(setValues, cv.Name, cv.Value)
237			}
238		}
239		if req.Namespace == "" {
240			return fmt.Errorf("namespace is required for installing AI Suite in cluster")
241		}
242	
243		req.Values = setValues
244		return c.apiserverGetter.InstallRelease(clusterCode, req)
245	}
