90	func (c *HelmClient) Install(installReleaseRequest *models.InstallOrUpgradeReleaseRequest) (*release.Release, error) {
91		namespace := installReleaseRequest.Namespace
92		name := installReleaseRequest.Name
93		repoChart := installReleaseRequest.RepoChart
94		version := installReleaseRequest.Version
95		dryRun := installReleaseRequest.DryRun
96		values := installReleaseRequest.Values
97		labels := installReleaseRequest.Labels
98		host, username, password := installReleaseRequest.HelmRepository.Host, installReleaseRequest.HelmRepository.UserName, installReleaseRequest.HelmRepository.Password
99	
100		log.Infof("Install release: namespace=%s, name=%s, repoChart=%s, version=%s, dryRun=%v", namespace, name, repoChart, version, dryRun)
101		if namespace == "" {
102			namespace = "default"
103		}
104		hc, err := c.HelmConfig(namespace)
105		if err != nil {
106			return nil, fmt.Errorf("failed to get helm config for namespace %s: %w", namespace, err)
107		}
108	
109		registryClient, err := c.GetRegistryClient(host, username, password)
110		if err != nil {
111			return nil, fmt.Errorf("failed to get registry client: %w", err)
112		}
113		// install
114	
115		installClient := action.NewInstall(hc)
116		installClient.CreateNamespace = installReleaseRequest.CreateNamespace
117		installClient.Namespace = namespace
118		installClient.ReleaseName = name
119		installClient.Wait = installReleaseRequest.Wait
120		if installReleaseRequest.Timeout > 0 {
121			installClient.Timeout = installReleaseRequest.Timeout
122		} else {
123			installClient.Timeout = 5 * time.Minute
124		}
125		installClient.Version = version
126		installClient.SetRegistryClient(registryClient)
127		installClient.Labels = labels
128		if dryRun {
129			installClient.DryRun = true
130			installClient.DryRunOption = "server"
131		}
132	
133		chart, err := locateChart(installClient.ChartPathOptions, repoChart, c.Settings)
134		if err != nil {
135			return nil, err
136		}
137	
138		rel, err := installClient.Run(chart, values)
139		if err != nil {
140			return nil, fmt.Errorf("failed to install release %s in namespace %s: %w", name, namespace, err)
141		}
142		return rel, nil
143	}
144	
145	func locateChart(pathOpts action.ChartPathOptions, chart string, settings *cli.EnvSettings) (*chart.Chart, error) {
146		// from cmd/helm/install.go and cmd/helm/upgrade.go
147		cp, err := pathOpts.LocateChart(chart, settings)
148		if err != nil {
149			return nil, err
150		}
151	
152		log.Debugf("Located chart %s: %s\n", chart, cp)
153	
154		p := getter.All(settings)
155	
156		// Check chart dependencies to make sure all are present in /charts
157		chartRequested, err := loader.Load(cp)
158		if err != nil {
159			return nil, err
160		}
161	
162		if err := checkIfInstallable(chartRequested); err != nil {
163			return nil, err
164		}
165	
166		registryClient, err := registry.NewClient(
167			registry.ClientOptDebug(false),
168			registry.ClientOptEnableCache(true),
169			//registry.ClientOptWriter(out),
170			registry.ClientOptCredentialsFile(settings.RegistryConfig),
171		)
172		if err != nil {
173			return nil, fmt.Errorf("failed to crete helm config object: %w", err)
174		}
175	
176		if req := chartRequested.Metadata.Dependencies; req != nil {
177			// If CheckDependencies returns an error, we have unfulfilled dependencies.
178			// As of Helm 2.4.0, this is treated as a stopping condition:
179			// https://github.com/helm/helm/issues/2209
180			if err := action.CheckDependencies(chartRequested, req); err != nil {
181				man := &downloader.Manager{
182					Out:              io.Discard,
183					ChartPath:        cp,
184					Keyring:          pathOpts.Keyring,
185					SkipUpdate:       false,
186					Getters:          p,
187					RepositoryConfig: settings.RepositoryConfig,
188					RepositoryCache:  settings.RepositoryCache,
189					Debug:            settings.Debug,
190					RegistryClient:   registryClient, // added on top of Helm code
191				}
192				if err := man.Update(); err != nil {
193					return nil, err
194				}
195				// Reload the chart with the updated Chart.lock file.
196				if chartRequested, err = loader.Load(cp); err != nil {
197					return nil, fmt.Errorf("failed reloading chart after repo update: %w", err)
198				}
199			}
200		}
201	
202		return chartRequested, nil
203	}
