220	func (c *HelmClient) Upgrade(upgradeReleaseRequest *models.InstallOrUpgradeReleaseRequest) (*release.Release, error) {
221		namespace := upgradeReleaseRequest.Namespace
222		name := upgradeReleaseRequest.Name
223		repoChart := upgradeReleaseRequest.RepoChart
224		version := upgradeReleaseRequest.Version
225		dryRun := upgradeReleaseRequest.DryRun
226		values := upgradeReleaseRequest.Values
227		host, username, password := upgradeReleaseRequest.HelmRepository.Host, upgradeReleaseRequest.HelmRepository.UserName, upgradeReleaseRequest.HelmRepository.Password
228	
229		log.Infof("Upgrade release: repoChart=%s, version=%s, dryRun=%v", repoChart, version, dryRun)
230		hc, err := c.HelmConfig(namespace)
231		if err != nil {
232			return nil, fmt.Errorf("failed to get helm config for namespace %s: %w", namespace, err)
233		}
234	
235		registryClient, err := c.GetRegistryClient(host, username, password)
236		if err != nil {
237			return nil, fmt.Errorf("failed to get registry client: %w", err)
238		}
239	
240		upgradeClient := action.NewUpgrade(hc)
241		upgradeClient.MaxHistory = 10
242		upgradeClient.Namespace = namespace
243		upgradeClient.Version = version
244		upgradeClient.PlainHTTP = true
245		upgradeClient.Wait = upgradeReleaseRequest.Wait
246		upgradeClient.SetRegistryClient(registryClient)
247	
248		if dryRun {
249			upgradeClient.DryRun = true
250			upgradeClient.DryRunOption = "server"
251		}
252		upgradeClient.ResetValues = false
253	
254		chart, err := locateChart(upgradeClient.ChartPathOptions, repoChart, c.Settings)
255		if err != nil {
256			return nil, err
257		}
258		rel, err := upgradeClient.Run(name, chart, values)
259		if err != nil {
260			return nil, fmt.Errorf("failed to upgrade release %s in namespace %s: %w", name, namespace, err)
261		}
262		if !dryRun {
263			log.Infof("Upgraded release : %s/%s=>%s", namespace, name, rel.Version)
264		}
265		return rel, nil
266	}
