201	func clusterChanged(old, new *register.ApiserverInfo) bool {
202		if old == nil {
203			return true
204		}
205		if old.ClusterName != new.ClusterName || old.SelfServiceAddress != new.SelfServiceAddress ||
206			old.ClusterRegion != new.ClusterRegion || old.ClusterRegionName != new.ClusterRegionName ||
207			old.TDSCClusterName != new.TDSCClusterName || old.TDSCS3Endpoint != new.TDSCS3Endpoint ||
208			old.TDSCS3AccessKey != new.TDSCS3AccessKey || old.TDSCS3SecretKey != new.TDSCS3SecretKey ||
209			old.TDSCS3Bucket != new.TDSCS3Bucket || old.TDSCFSEndpoint != new.TDSCFSEndpoint ||
210			old.TDSCStorageClassName != new.TDSCStorageClassName || old.AuthenticationMode != new.AuthenticationMode ||
211			old.TapTTyAddress != new.TapTTyAddress || len(old.BasicAccounts) != len(new.BasicAccounts) ||
212			old.GatewayAddress != new.GatewayAddress || old.ClusterProperty != new.ClusterProperty {
213			return true
214		}
215		for i, oldAccount := range old.BasicAccounts {
216			if new.BasicAccounts[i] != oldAccount {
217				return true
218			}
219		}
220		return false
221	}
