226		if err != nil {
227			if errors.Is(err, gorm.ErrRecordNotFound) {
228				return nil, fmt.Errorf("clusterCode: %s, not found apiserver", clusterCode)
229			} else {
230				return nil, err
231			}
232		}
233		if !dbCluster.Health {
234			return nil, fmt.Errorf("clusterCode: %s, not found health apiserver", clusterCode)
235		}
236		return &(dbCluster.ApiserverInfo), nil
