254	func (ac *ApiserverCache) GetApiserverHeader(apiserver *register.ApiserverInfo) http.Header {
255		header := http.Header{}
256		switch apiserver.AuthenticationMode {
257		case middleware.AuthenticationModeBasicAuth:
258			for _, account := range apiserver.BasicAccounts {
259				if len(strings.Split(account, ":")) == 2 {
260					header.Set("Authorization", "Basic "+base64.StdEncoding.EncodeToString([]byte(account)))
261					break
262				}
263			}
264		}
265		return header
266	}
