326	type ApiserverClient struct {
327		address string
328		*http.Client
329		header http.Header
330	}
331	
332	func (ac *ApiserverClient) Do(method string, path string, query *url.Values, reqBody interface{}, response interface{}) error {
333		//path: /tap/api/v1/xxx
334		u := "http://" + ac.address + path
335		if query != nil {
336			u += "?" + query.Encode()
337		}
338		body, err := json.Marshal(reqBody)
339		if err != nil {
340			return err
341		}
342		b := bytes.NewReader(body)
343		req, err := http.NewRequest(method, u, b)
344		if err != nil {
345			return err
346		}
347		for key, value := range ac.header {
348			req.Header[key] = value
349		}
350		resp, err := ac.Client.Do(req)
351		if err != nil {
352			return err
353		}
354		defer resp.Body.Close()
355		respBody, err := io.ReadAll(resp.Body)
356		if err != nil {
357			return err
358		}
359		if resp.StatusCode != http.StatusOK {
360			return errors.New(string(respBody))
361		}
362		res := &models.Response{}
363		err = json.Unmarshal(respBody, res)
364		if err != nil {
365			return err
366		}
367		if res.Code != models.SuccessCode {
368			return errors.New(res.Msg)
369		}
370		//如果实际接口返回的就是nil直接返回，不参与下面的反序列化
371		if res.RespBody == nil || response == nil {
372			return nil
373		}
374		marshal, err := json.Marshal(res.RespBody)
375		if err != nil {
376			return err
377		}
378		return json.Unmarshal(marshal, response)
379	}
