381	func (ac *ApiserverClient) ProxyKubeConfig(method string, path string, query *url.Values, reqBody io.Reader) (*http.Response, error) {
382		// 拼接 URL
383		u := "http://" + ac.address + path
384		if query != nil {
385			u += "?" + query.Encode()
386		}
387	
388		req, err := http.NewRequest(method, u, reqBody)
389		if err != nil {
390			return nil, err
391		}
392	
393		for key, value := range ac.header {
394			req.Header[key] = value
395		}
396	
397		resp, err := ac.Client.Do(req)
398		if err != nil {
399			return nil, err
400		}
401	
402		return resp, nil
403	}
